#include <iostream>
#include <numeric>
#include <vector>

bool solve(long long n) {
    std::vector<int> digits;
    long long num = n;

    // Extract digits from n
    while (num > 0) {
        digits.push_back(num % 10);
        num /= 10;
    }

    // Calculate sum of digits
    long long sum = std::accumulate(digits.begin(), digits.end(), 0);

    // Calculate product of digits
    long long product = 1;
    for (int digit : digits) {
        product *= digit;
    }

    // Check if n is divisible by the sum of the sum and product
    return n % (sum + product) == 0;
}
